from flask import Blueprint, render_template_string, request, flash, redirect, url_for

auth_bp = Blueprint('auth_bp', __name__)

@auth_bp.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        if username == 'user' and password == 'pass':
            # Gerçek bir uygulamada burada oturum açma işlemi yapılır
            return render_template_string("<h2>Giriş Başarılı!</h2><p>Hoş geldin, {{ username }}</p><p><a href='/'>Ana Sayfa</a></p>", username=username)
        else:
            return render_template_string("<h2>Giriş Başarısız!</h2><p>Kullanıcı adı veya şifre hatalı.</p><p><a href='/auth/login'>Tekrar Dene</a></p>")
    return render_template_string("""
        <h1>Giriş Yap</h1>
        <form method="post">
            <label for="username">Kullanıcı Adı:</label><br>
            <input type="text" id="username" name="username"><br>
            <label for="password">Şifre:</label><br>
            <input type="password" id="password" name="password"><br><br>
            <input type="submit" value="Giriş">
        </form>
        <p>Kullanıcı Adı: user, Şifre: pass</p>
        <p><a href='/'>Ana Sayfa</a></p>
    """)

@auth_bp.route('/logout')
def logout():
    # Gerçek bir uygulamada burada oturum kapatma işlemi yapılır
    return render_template_string("<h2>Çıkış Yaptınız</h2><p><a href='/'>Ana Sayfa</a></p>")
